public void initFromSalesAgreementHeader(SalesAgreementHeader _salesHeader)
{

    ETG_SalesAgreementHeader    eTG_SalesAgreementHeader;

    next initFromSalesAgreementHeader( _salesHeader);

    select firstonly * from eTG_SalesAgreementHeader 
        where eTG_SalesAgreementHeader.SalesAgreementId == _salesHeader.SalesNumberSequence;

    this.ETG_DeliveryDescription              = eTG_SalesAgreementHeader.DeliveryDescription;
    this.ETG_TermPaymDescription              = eTG_SalesAgreementHeader.TermPaymDescription;
    this.ETG_Future                           = eTG_SalesAgreementHeader.Future;
    this.ETG_Consignee                        = eTG_SalesAgreementHeader.Consignee;
    this.ETG_OnAccountOf                      = eTG_SalesAgreementHeader.OnAccountOf;
    this.ETG_Notes                            = eTG_SalesAgreementHeader.Notes;
    this.ETG_Through                          = eTG_SalesAgreementHeader.Through;
    this.ETG_Notifytodifferentparty           = eTG_SalesAgreementHeader.Notifytodifferentparty;
    this.ETG_BuyerBank                        = eTG_SalesAgreementHeader.BuyerBank;
    this.ETG_SellerBank                       = eTG_SalesAgreementHeader.SellerBank;
    this.ETG_SellerAccountNum                 = eTG_SalesAgreementHeader.SellerAccountNum;
    this.ETG_PricingMonth                     = eTG_SalesAgreementHeader.PricingMonth;
    this.ETG_PricingFromDate                  = eTG_SalesAgreementHeader.PricingFromDate;
    this.ETG_PricingTodate                    = eTG_SalesAgreementHeader.PricingTodate;
    this.ETG_AdvanceDue                       = eTG_SalesAgreementHeader.AdvanceDue;
    this.ETG_FromDatePort                     = eTG_SalesAgreementHeader.FromDatePort;
    this.ETG_ToDatePort                       = eTG_SalesAgreementHeader.ToDatePort;
    this.ETG_PortOfLoading                    = eTG_SalesAgreementHeader.PortOfLoading;
    this.ETG_PortOfDischarge                  = eTG_SalesAgreementHeader.PortOfDischarge;
    this.ETG_CustomImport                     = eTG_SalesAgreementHeader.CustomImport;
    this.ETG_ImportDate                       = eTG_SalesAgreementHeader.ImportDate;
    this.ETG_Number                           = eTG_SalesAgreementHeader.Number;
    this.ETG_CommissionType                   = eTG_SalesAgreementHeader.CommissionType;
    this.ETG_TypeValue                        = eTG_SalesAgreementHeader.TypeValue;
    this.ETG_DisplayTotalCalculatedCommission = eTG_SalesAgreementHeader.DisplayTotalCalculatedCommission;
    this.ETG_TermsOfDelDescription  = eTG_SalesAgreementHeader.TermsOfDelDescription;
    this.ETG_SalesPoolId            = eTG_SalesAgreementHeader.SalesPoolId;
    this.ETG_BuyerDeliveryAddress   = eTG_SalesAgreementHeader.BuyerDeliveryAddress;
    this.ETG_SellerDeliveryAddress  = eTG_SalesAgreementHeader.SellerDeliveryAddress;
    this.ETG_BuyerAccountNum        = eTG_SalesAgreementHeader.BuyerAccountNum;
    this.ETG_Sellersecondarybank    = eTG_SalesAgreementHeader.Sellersecondarybank;
    this.ETG_Buyersecondarybank     = eTG_SalesAgreementHeader.Buyersecondarybank;
    this.ETG_Name                   = eTG_SalesAgreementHeader.Name;
    this.ETG_Address                = eTG_SalesAgreementHeader.Address;
    this.ETG_PortOfLoadingDesc      = eTG_SalesAgreementHeader.PortOfLoadingDesc;
    this.ETG_PortOfDischargeDesc    = eTG_SalesAgreementHeader.PortOfDischargeDesc;
    this.ETG_ShipperBuyer           = eTG_SalesAgreementHeader.ShipperBuyer;
    this.ETG_BuyerName              = eTG_SalesAgreementHeader.buyerName();
    this.ETG_SellerName             = eTG_SalesAgreementHeader.sellerName();
    this.ETG_BrokerName             = eTG_SalesAgreementHeader.brokerName();
    this.ETG_AgreementType          = eTG_SalesAgreementHeader.AgreementType;
    this.ETG_QuantityConditions     = eTG_SalesAgreementHeader.QuantityConditions;
    this.ETG_PermitNumber           = eTG_SalesAgreementHeader.PermitNumber;
    this.ETG_PackingGroup           = eTG_SalesAgreementHeader.PackingGroup;

}
